'use client';

import { AlertTriangle } from 'lucide-react';
import { AppModal } from './Modal';
import { GlowButton } from './GlowButton';

export interface ConfirmState {
  show: boolean;
  message: string;
  onConfirm: (() => void) | null;
  type: 'confirm' | 'alert';
}

export const initialConfirmState: ConfirmState = {
  show: false,
  message: '',
  onConfirm: null,
  type: 'confirm',
};

interface ConfirmDialogProps {
  state: ConfirmState;
  onCancel: () => void;
  onConfirm: () => void;
}

export function ConfirmDialog({ state, onCancel, onConfirm }: ConfirmDialogProps) {
  const isAlert = state.type === 'alert';
  return (
    <AppModal
      isOpen={state.show}
      onClose={isAlert ? onCancel : onCancel}
      size="sm"
      level={90}
      dismissable={isAlert}
    >
      <div className="flex items-start gap-4 px-6 pt-6">
        <div
          className={
            isAlert
              ? 'grid size-12 shrink-0 place-items-center rounded-2xl border border-[oklch(0.85_0.16_82/0.4)] bg-[oklch(0.85_0.16_82/0.14)] text-[oklch(0.9_0.14_88)]'
              : 'grid size-12 shrink-0 place-items-center rounded-2xl border border-[oklch(0.68_0.25_14/0.4)] bg-[oklch(0.68_0.25_14/0.14)] text-[oklch(0.8_0.2_16)]'
          }
        >
          <AlertTriangle size={24} />
        </div>
        <div className="min-w-0 flex-1 pt-1">
          <h3 className="font-display text-lg font-semibold text-white">
            {isAlert ? 'Atenção' : 'Confirmar ação'}
          </h3>
          <p className="mt-1.5 text-sm whitespace-pre-line text-white/60">{state.message}</p>
        </div>
      </div>
      <div className="flex items-center justify-end gap-3 px-6 py-5">
        {!isAlert && (
          <GlowButton tone="ghost" onClick={onCancel}>
            Cancelar
          </GlowButton>
        )}
        <GlowButton tone={isAlert ? 'accent' : 'negative'} onClick={onConfirm}>
          {isAlert ? 'OK' : 'Confirmar'}
        </GlowButton>
      </div>
    </AppModal>
  );
}
